INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00357', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關刑案現場之處置，下列敘述何者正確？', '["於刑案現場逮捕犯罪嫌疑人時，應立即帶離；於刑案現場以外之處所逮捕時，不可帶回現場", "封鎖犯罪現場時，應派員於封鎖線內警戒，非經現場指揮官同意，任何人不得進入，經許可進 入現場者，應著必要之防護裝備，避免破壞現場跡證", "刑案現場封鎖範圍及層數，應視現場環境及事實需要而定，初期封鎖之範圍應小，待初步勘察 後，視實際需要再行界定封鎖範圍", "刑案現場應依任務需要，將現有人員區分為調查組及警戒組，警戒組負責警戒、勘察現場，調 查組負責現場及鄰近地區之調查、訪問"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00358', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關刑案現場勘察、測繪，下列敘述何者錯誤？', '["勘察刑案現場，宜由跡證明顯者先行勘察，再逐步發掘潛伏之跡證", "勘察刑案現場，宜由地面開始勘察，依次是門、窗、牆壁，而後及於天花板", "現場測繪宜先從重要跡證之相關位置開始，其次為現場，最後為現場周圍", "現場範圍廣闊者，宜尋找制高點，進行全面觀察"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00359', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '執行跟蹤過程中，被跟蹤對象如已懷疑被跟蹤，且欲向執行人員詢問時，執行人員之應變措施， 下列敘述何者最佳？', '["若無其事，並保持自然行走狀態", "佯裝向人問路、交談", "立即停止跟蹤，重新部署", "保持鎮靜，並準備若干合理說詞及因應作為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00360', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲用乙的手機猛力擲向乙的頭部，致乙頭破流血，手機毀壞。下列敘述何者正確？', '["檢察官就甲傷害部分提起公訴，就毀損部分為不起訴處分時，公訴之效力不及於毀損部分", "乙提起告訴之後又撤回告訴，檢察官以告訴經撤回為由，為不起訴處分，並已逾再議期間，乙 之配偶又於告訴期間提起告訴，因不起訴處分已具形式確定力，故檢察官不得再行起訴", "乙提起傷害自訴後，檢察官就傷害部分為不起訴處分，不起訴處分無效", "檢察官就本案以犯罪嫌疑不足為由，為不起訴處分，如經確定者，因具有實質確定力，雖嗣後 有發現新事實或新證據，仍不得就同一案件再行起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00361', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依警察偵查犯罪手冊之規定，有關幫派涉及組織犯罪案件之處理，下列敘述何者錯誤？', '["偵辦幫派涉組織犯罪案件，應對犯罪組織與其成員實際支配相關第三人所有財產之來源及流向 詳細查明，並依法扣押", "幫派涉組織犯罪案件之偵查，應對犯罪組織結構、幫派背景與成員身分加以釐清，並載明於移 送書或報告書", "對幫派涉組織犯罪案件之被害人，應依證人保護法及組織犯罪防制條例規定，克盡保密與保護 之責任", "幫派涉組織犯罪案件檢舉人身分資料，應另行封存，併入移送法院審理文書之同一卷宗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00362', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '行為人甲涉嫌欲以電話詐騙之手法詐取被害人乙之財物，甲以電話與乙通訊欲詐騙乙之財物時， 乙驚覺有異認為可能是詐騙電話，乃於甲、乙二人電話通訊之際，將二人之通訊對話內容予以秘 密錄音，嗣將該通訊對話內容之錄音作為告發甲涉嫌詐欺取財犯行之證據。關於上開乙秘密錄音 通訊對話內容之證據，下列敘述何者正確？', '["乙秘密錄音通訊對話內容，有證據排除法則之適用，無證據能力", "乙秘密錄音通訊對話內容，有證據排除法則之適用，有證據能力", "乙秘密錄音通訊對話內容，無證據排除法則之適用，無證據能力", "乙秘密錄音通訊對話內容，無證據排除法則之適用，有證據能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00363', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲、乙二人於警詢犯罪嫌疑人丙時，向丙曉諭如其自白犯罪將可獲得減免刑責之法定 寬典，丙乃因此而向甲、乙自承犯罪。關於上開丙自承犯罪之供述，下列敘述何者正確？', '["屬利誘之自白，由法院依個案權衡審酌其有無證據能力", "屬利誘之自白，不具證據能力", "屬任意性之自白，具證據能力", "屬非任意性之自白，不具證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00364', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲涉嫌殺人案件，為證明自身之清白，乃委請其多年好友同時亦係國內外知名刑事鑑識專家乙， 以其刑事鑑識專家之身分對甲案作成刑事鑑定意見書，提供偵審機關審酌。關於上開乙所作成之 刑事鑑定意見書，下列敘述何者正確？', '["屬專家證言，原則上具證據能力", "屬鑑定人之鑑定意見，原則上具證據能力", "屬傳聞證據，原則上不具證據能力", "屬文書證據，原則上不具證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00365', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關子彈、彈頭、彈殼證物之處理原則，下列敘述何者正確？', '["現場彈殼採取前宜先記錄其原始狀態，並視個案情況留意其上可能之微物跡證，必要時宜先採 集鑑定", "採取彈頭、彈殼時應以金屬夾直接夾取", "相同規格之彈頭、彈殼宜集中包裝於同一證物袋", "有供比對用之同廠牌子彈，應準備一至二顆送鑑定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00366', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官甲、乙二人於執行巡邏勤務時途經某路段，經路人丙通報附近某商店內刻正發生強盜 案件，甲、乙乃即刻前往刑案現場並依法逮捕現行犯丁。依據刑事訴訟法之相關規定，下列敘述 何者正確？', '["甲、乙得經丁之同意後，至丁宅中搜索，搜索完畢後，並應於3日內向該管檢察官及法院報告", "甲、乙得在未經丁之同意下，立即搜索丁使用中之交通工具，搜索完畢後，無庸於3日內向該 管檢察官及法院報告", "情況急迫，甲、乙得因丁之供述，對非現行犯之共謀共同正犯戊，不經約談傳喚逕行拘提戊， 並應於3日內向該管檢察官及法院報告", "情況急迫，甲、乙得因丁之供述，對非現行犯之共謀共同正犯戊，逕行進入戊宅中實施逕行拘 提戊，無庸於3日內向該管檢察官及法院報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "c2a4f570d331", "answer_pdf_sha1": "5a7723a70989", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1409", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
